/**
 * Version freshness checks for sequant
 *
 * Provides utilities to check if the current version is up to date
 * with the latest version on npm.
 */

import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const PACKAGE_NAME = "sequant";
const NPM_REGISTRY_URL = `https://registry.npmjs.org/${PACKAGE_NAME}/latest`;
const VERSION_CHECK_TIMEOUT = 3000; // 3 seconds
const CACHE_EXPIRY_MS = 24 * 60 * 60 * 1000; // 24 hours

export interface VersionCache {
  latestVersion: string;
  checkedAt: string;
}

export interface VersionCheckResult {
  currentVersion: string;
  latestVersion: string | null;
  isOutdated: boolean;
  isLocalInstall?: boolean;
  error?: string;

/**
 * Package manager command configuration
 */
export interface PackageManagerConfig {
  run: string; // e.g., "npm run", "bun run", "yarn"
  exec: string; // e.g., "npx", "bunx", "yarn dlx"
  install: string; // e.g., "npm install", "bun install"
  installSilent: string; // e.g., "npm install --silent", "bun install --silent"
}

/**
 * Package manager configurations
 */
export const PM_CONFIG: Record<PackageManager, PackageManagerConfig> = {
  npm: {
    run: "npm run",
    exec: "npx",
    install: "npm install",
    installSilent: "npm install --silent",
  },
  bun: {
    run: "bun run",
    exec: "bunx",
    install: "bun install",
    installSilent: "bun install --silent",
  },
  yarn: {
    run: "yarn",
    exec: "yarn dlx",
    install: "yarn install",
    installSilent: "yarn install --silent",
  },
  pnpm: {
    run: "pnpm run",
    exec: "pnpm dlx",
    install: "pnpm install",
    installSilent: "pnpm install --silent",
  },
  // Python package managers
  pip: {
    run: "python -m",
    exec: "python -m",
    install: "pip install",
    installSilent: "pip install -q",
  },
  poetry: {
    run: "poetry run",
    exec: "poetry run",
    install: "poetry install",
    installSilent: "poetry install -q",
  },
  uv: {
    run: "uv run",
    exec: "uvx",
    install: "uv pip install",
    installSilent: "uv pip install -q",
  },
};

