      mockFetch.mockRejectedValue(new Error("Network error"));

      const result = await checkVersionThorough();

      expect(result.latestVersion).toBeNull();
      expect(result.isOutdated).toBe(false);
      expect(result.error).toBeDefined();
    });
  });

