      const version = await fetchLatestVersion();
      expect(version).toBeNull();
    });

    it("returns null on timeout", async () => {
      mockFetch.mockImplementation(
        () =>
          new Promise((_, reject) => {
            setTimeout(() => reject(new Error("Aborted")), 100);
          }),
      );

